import Link from 'next/link';
import Image from 'next/image';
import { getAllCapsules } from '@/lib/notion';
import { createServerSupabaseClient } from '@/lib/supabase';
import type { Capsule } from '@/types';

interface ReviewStat {
  capsule_slug: string;
  avg_rating: number;
  review_count: number;
}

export async function TopCapsules() {
  // Notion + Supabase 병렬 조회
  const [allCapsules, statsResult] = await Promise.all([
    getAllCapsules().catch(() => [] as Capsule[]),
    createServerSupabaseClient()
      .from('capsule_review_stats')
      .select('capsule_slug, avg_rating, review_count')
      .then(({ data }) => data as ReviewStat[] | null)
      .catch(() => null),
  ]);

  // 쿠팡 평점 Top 5 (coupangRating DESC, null 제외)
  const coupangTop5 = allCapsules.length > 0
    ? [...allCapsules]
        .filter((c) => c.coupangRating !== null)
        .sort((a, b) => (b.coupangRating ?? 0) - (a.coupangRating ?? 0))
        .slice(0, 5)
    : null;

  // 서비스 평점 Top 5 (review_count >= 5, avg_rating DESC)
  const capsuleMap = new Map(allCapsules.map((c) => [c.slug, c]));
  const serviceTop5 = statsResult
    ? statsResult
        .filter((s) => s.review_count >= 5)
        .sort((a, b) => b.avg_rating - a.avg_rating)
        .slice(0, 5)
        .map((s) => ({ stat: s, capsule: capsuleMap.get(s.capsule_slug) }))
        .filter((item) => item.capsule !== undefined)
    : null;

  return (
    <section className="py-12">
      <h2 className="text-2xl font-bold mb-8">캡슐 Top 5 랭킹</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* 쿠팡 평점 Top 5 */}
        {coupangTop5 !== null && (
          <div>
            <h3 className="text-lg font-semibold mb-4">쿠팡 평점 Top 5</h3>
            <ol className="space-y-3">
              {coupangTop5.map((capsule, i) => (
                <li key={capsule.id}>
                  <Link href={`/capsules/${capsule.slug}`} className="flex items-center gap-3 p-3 rounded-lg hover:bg-muted transition-colors">
                    <span className="text-lg font-bold text-muted-foreground w-6">{i + 1}</span>
                    {capsule.imageUrl && (
                      <Image src={capsule.imageUrl} alt={capsule.name} width={40} height={40} className="rounded object-cover" />
                    )}
                    <div className="flex-1 min-w-0">
                      <p className="font-medium truncate">{capsule.name}</p>
                      <p className="text-sm text-muted-foreground">{capsule.brandName}</p>
                    </div>
                    <span className="text-sm font-semibold">{capsule.coupangRating?.toFixed(1)}점</span>
                  </Link>
                </li>
              ))}
            </ol>
          </div>
        )}
        {/* 서비스 평점 Top 5 */}
        <div>
          <h3 className="text-lg font-semibold mb-4">서비스 평점 Top 5</h3>
          {serviceTop5 === null || serviceTop5.length === 0 ? (
            <p className="text-muted-foreground text-sm py-8 text-center">아직 충분한 리뷰가 없습니다.</p>
          ) : (
            <ol className="space-y-3">
              {serviceTop5.map(({ stat, capsule }, i) => capsule && (
                <li key={capsule.id}>
                  <Link href={`/capsules/${capsule.slug}`} className="flex items-center gap-3 p-3 rounded-lg hover:bg-muted transition-colors">
                    <span className="text-lg font-bold text-muted-foreground w-6">{i + 1}</span>
                    {capsule.imageUrl && (
                      <Image src={capsule.imageUrl} alt={capsule.name} width={40} height={40} className="rounded object-cover" />
                    )}
                    <div className="flex-1 min-w-0">
                      <p className="font-medium truncate">{capsule.name}</p>
                      <p className="text-sm text-muted-foreground">{capsule.brandName}</p>
                    </div>
                    <span className="text-sm font-semibold">{stat.avg_rating.toFixed(1)}점</span>
                  </Link>
                </li>
              ))}
            </ol>
          )}
        </div>
      </div>
    </section>
  );
}
```

에러 처리: Notion 조회 실패 시 coupangTop5가 null이 되어 쿠팡 열을 숨기고, Supabase 조회 실패 시 serviceTop5가 null이 되어 "아직 충분한 리뷰가 없습니다" 문구를 표시한다.

frontend/app/api/posts/route.ts의 GET 함수를 수정한다.

구현 내용:
```typescript
import { mapRowToPost, type PostRow } from '@/lib/mappers';
import type { PaginatedResponse } from '@/types';
import type { Post } from '@/types';

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const category = searchParams.get('category');
  const cursor = searchParams.get('cursor'); // ISO 문자열 (created_at)
  const limit = Math.min(parseInt(searchParams.get('limit') ?? '10', 10), 50);

  const supabase = createServerSupabaseClient();
  let query = supabase
    .from('posts')
    .select('*')
    .order('created_at', { ascending: false })
    .limit(limit + 1); // N+1 패턴으로 hasMore 판별

  if (category) {
    query = query.eq('category', category);
  }

  // cursor가 있으면 해당 시점 이전 데이터 조회
  if (cursor) {
    query = query.lt('created_at', cursor);
  }

  const { data, error } = await query;
  if (error) return NextResponse.json({ error: error.message }, { status: 500 });

  const rows = data as PostRow[];
  const hasMore = rows.length > limit;
  const items = hasMore ? rows.slice(0, limit) : rows;
  const nextCursor = hasMore ? items[items.length - 1].created_at : null;

  const response: PaginatedResponse<Post> = {
    data: items.map(mapRowToPost),
    nextCursor,
    hasMore,
  };

  return NextResponse.json(response);
}
```

cursor 파라미터 없을 때 첫 페이지 반환하여 하위 호환성 유지.

