```typescript
import type { PaginatedResponse } from '@/types';

export async function getPosts(params?: {
  category?: string;
  cursor?: string;
  limit?: number;
}): Promise<PaginatedResponse<Post>> {
  const urlParams = new URLSearchParams();
  if (params?.category) urlParams.set('category', params.category);
  if (params?.cursor) urlParams.set('cursor', params.cursor);
  if (params?.limit) urlParams.set('limit', String(params.limit));

  const query = urlParams.toString();
  const url = query
    ? `${BASE_URL}/api/posts?${query}`
    : `${BASE_URL}/api/posts`;

  const res = await fetch(url);
  if (!res.ok) throw new Error('게시글을 불러오지 못했습니다.');
  return res.json();
}
```

PaginatedResponse import를 상단에 추가하고, 기존 getPosts 호출 위치가 있다면 반환 타입 변경에 맞게 소비 코드도 점검한다.

frontend/components/community/post-list-infinite.tsx 파일을 신규 생성한다.

구현 내용:
```typescript
'use client';

import { useEffect, useRef } from 'react';
import { useInfiniteQuery } from '@tanstack/react-query';
import { getPosts } from '@/lib/api';
import { PostCard } from './post-card';
import { Skeleton } from '@/components/ui/skeleton';
import type { PaginatedResponse } from '@/types';
import type { Post } from '@/types';

interface Props {
  initialData: PaginatedResponse<Post>;
  category?: string;
}

export function PostListInfinite({ initialData, category }: Props) {
  const bottomRef = useRef<HTMLDivElement>(null);

  const {
    data,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
  } = useInfiniteQuery({
    queryKey: ['posts', category ?? 'all'],
    queryFn: ({ pageParam }) =>
      getPosts({ category, cursor: pageParam as string | undefined, limit: 10 }),
    initialPageParam: undefined as string | undefined,
    getNextPageParam: (lastPage) =>
      lastPage.hasMore ? lastPage.nextCursor ?? undefined : undefined,
    initialData: {
      pages: [initialData],
      pageParams: [undefined],
    },
  });

  // IntersectionObserver로 하단 감지 시 다음 페이지 로드
  useEffect(() => {
    const el = bottomRef.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && hasNextPage && !isFetchingNextPage) {
          fetchNextPage();
        }
      },
      { threshold: 0.1 }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [hasNextPage, isFetchingNextPage, fetchNextPage]);

  const posts = data?.pages.flatMap((p) => p.data) ?? [];

  return (
    <div>
      <div className="flex flex-col gap-2">
        {posts.map((post) => (
          <PostCard key={post.id} post={post} />
        ))}
      </div>

      {/* 스켈레톤 로딩 */}
      {isFetchingNextPage && (
        <div className="flex flex-col gap-2 mt-2">
          {Array.from({ length: 3 }).map((_, i) => (
            <Skeleton key={i} className="h-20 w-full rounded-lg" />
          ))}
        </div>
      )}

      {/* 하단 감지 요소 */}
      <div ref={bottomRef} className="h-1" />

      {/* 모든 게시글 로드 완료 */}
      {!hasNextPage && posts.length > 0 && (
        <p className="text-center text-sm text-muted-foreground py-6">
          모든 게시글을 확인했습니다.
        </p>
      )}
    </div>
  );
}
```

카테고리 전환 시 queryKey에 category를 포함하여 캐시 분리 및 첫 페이지부터 재조회가 자동으로 이루어진다.

