```typescript
'use client';

import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
import { getReviews } from '@/lib/api';
import { StarRating } from './star-rating';
import { ReviewForm } from './review-form';
import { Button } from '@/components/ui/button';
import { Separator } from '@/components/ui/separator';
import { Loader2 } from 'lucide-react';
import type { PaginatedResponse } from '@/types';
import type { Review } from '@/types';

interface Props {
  capsuleId: string;
  capsuleSlug: string;
  initialData: PaginatedResponse<Review>;
}

export function ReviewListInfinite({ capsuleId, capsuleSlug, initialData }: Props) {
  const queryClient = useQueryClient();

  const {
    data,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
  } = useInfiniteQuery({
    queryKey: ['reviews', capsuleSlug],
    queryFn: ({ pageParam }) =>
      getReviews(capsuleSlug, { cursor: pageParam as string | undefined, limit: 5 }),
    initialPageParam: undefined as string | undefined,
    getNextPageParam: (lastPage) =>
      lastPage.hasMore ? lastPage.nextCursor ?? undefined : undefined,
    initialData: {
      pages: [initialData],
      pageParams: [undefined],
    },
  });

  const reviews = data?.pages.flatMap((p) => p.data) ?? [];

  // 리뷰 작성 성공 시 캐시 무효화
  const handleReviewSuccess = () => {
    queryClient.invalidateQueries({ queryKey: ['reviews', capsuleSlug] });
  };

  return (
    <div>
      <h2 className="text-xl font-bold mb-6">리뷰 ({reviews.length})</h2>

      {reviews.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">
          아직 리뷰가 없습니다. 첫 번째 리뷰를 남겨보세요.
        </div>
      ) : (
        <div className="space-y-4">
          {reviews.map((review, index) => (
            <div key={review.id}>
              <div className="space-y-2 py-4">
                <div className="flex items-center justify-between">
                  <span className="font-medium">{review.authorNickname}</span>
                  <time className="text-sm text-muted-foreground">
                    {new Date(review.createdAt).toLocaleDateString('ko-KR')}
                  </time>
                </div>
                <StarRating value={review.rating} size="sm" />
                <p className="text-sm leading-relaxed">{review.content}</p>
              </div>
              {index < reviews.length - 1 && <Separator />}
            </div>
          ))}
        </div>
      )}

      {/* 더보기 버튼 */}
      {hasNextPage && (
        <div className="mt-6 text-center">
          <Button
            variant="outline"
            onClick={() => fetchNextPage()}
            disabled={isFetchingNextPage}
          >
            {isFetchingNextPage ? (
              <><Loader2 className="mr-2 h-4 w-4 animate-spin" />불러오는 중...</>
            ) : (
              '더보기'
            )}
          </Button>
        </div>
      )}

      <Separator className="my-10" />

      <section>
        <h2 className="text-xl font-bold mb-6">리뷰 작성</h2>
        <ReviewForm
          capsuleId={capsuleId}
          capsuleSlug={capsuleSlug}
          onSuccess={handleReviewSuccess}
        />
      </section>
    </div>
  );
}
```

